"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[3816],{73971(n,e,r){r.r(e),r.d(e,{assets:()=>o,contentTitle:()=>c,default:()=>l,frontMatter:()=>d,metadata:()=>t,toc:()=>u});const t=JSON.parse('{"id":"cpp14/exchange","title":"std::exchange","description":"C++14 std::exchange \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp14/10-exchange.md","sourceDirName":"cpp14","slug":"/cpp14/10-exchange","permalink":"/LearnModernCpp/docs/cpp14/10-exchange","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp14","permalink":"/LearnModernCpp/docs/tags/cpp-14"},{"inline":true,"label":"exchange","permalink":"/LearnModernCpp/docs/tags/exchange"}],"version":"current","sidebarPosition":11,"frontMatter":{"sidebar_position":11,"slug":"10-exchange","title":"std::exchange","description":"C++14 std::exchange \u6559\u5b66\u793a\u4f8b","tags":["cpp14","exchange"]},"sidebar":"docs","previous":{"title":"integer_sequence\u4e0eindex_sequence","permalink":"/LearnModernCpp/docs/cpp14/09-integer-sequence"},"next":{"title":"std::quoted","permalink":"/LearnModernCpp/docs/cpp14/11-quoted"}}');var a=r(74848),s=r(28453);const d={sidebar_position:11,slug:"10-exchange",title:"std::exchange",description:"C++14 std::exchange \u6559\u5b66\u793a\u4f8b",tags:["cpp14","exchange"]},c="std::exchange",o={},u=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function i(n){const e={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,s.R)(),...n.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(e.header,{children:(0,a.jsx)(e.h1,{id:"stdexchange",children:"std::exchange"})}),"\n",(0,a.jsx)(e.p,{children:"C++14 \u6807\u51c6\u5f15\u5165\u7684 std::exchange \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,a.jsx)(e.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,a.jsx)(e.pre,{children:(0,a.jsx)(e.code,{className:"language-cpp",metastring:'title="cpp14/10_exchange.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: std::exchange\r\n * \u6240\u5c5e\u6807\u51c6: C++14\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: std::exchange(obj, new_value) \u5c06obj\u7684\u503c\u66ff\u6362\u4e3anew_value\uff0c\r\n *          \u540c\u65f6\u8fd4\u56deobj\u7684\u65e7\u503c\u3002\u5b83\u662f\u4e00\u4e2a\u7b80\u5355\u4f46\u975e\u5e38\u5b9e\u7528\u7684\u5de5\u5177\u51fd\u6570\uff0c\r\n *          \u5b9a\u4e49\u5728<utility>\u5934\u6587\u4ef6\u4e2d\u3002\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: \u5728\u79fb\u52a8\u8bed\u4e49\u7684\u5b9e\u73b0\u4e2d\uff0c\u7ecf\u5e38\u9700\u8981"\u53d6\u51fa\u65e7\u503c\u5e76\u66ff\u6362\u4e3a\u9ed8\u8ba4\u503c"\u7684\u64cd\u4f5c\u3002\r\n *              \u6ca1\u6709exchange\u65f6\uff0c\u9700\u8981\u4e34\u65f6\u53d8\u91cf\u6765\u4fdd\u5b58\u65e7\u503c\uff0c\u4ee3\u7801\u5197\u957f\u4e14\u5bb9\u6613\u51fa\u9519\u3002\r\n *              exchange\u5c06\u8fd9\u4e2a\u5e38\u89c1\u6a21\u5f0f\u5c01\u88c5\u4e3a\u4e00\u884c\u4ee3\u7801\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - exchange(obj, new_val) \u7b49\u4ef7\u4e8e { auto old = move(obj); obj = new_val; return old; }\r\n *   - \u6700\u5e38\u7528\u4e8e\u7b80\u5316\u79fb\u52a8\u6784\u9020\u51fd\u6570\u548c\u79fb\u52a8\u8d4b\u503c\u8fd0\u7b97\u7b26\r\n *   - \u4e5f\u9002\u7528\u4e8e\u9700\u8981"\u8bfb\u53d6\u5e76\u91cd\u7f6e"\u7684\u573a\u666f\r\n *   - \u4e0d\u662f\u539f\u5b50\u64cd\u4f5c\uff0c\u4e0d\u7528\u4e8e\u591a\u7ebf\u7a0b\u540c\u6b65\r\n * ============================================================\r\n */\r\n\r\n#include <iostream>\r\n#include <utility>\r\n#include <string>\r\n#include <vector>\r\n#include <memory>\r\n#include <queue>\r\n#include <algorithm>\r\n\r\n// ============================================================\r\n// \u57fa\u7840\u7528\u6cd5\r\n// ============================================================\r\nvoid basic_usage() {\r\n    std::cout << "--- basic_usage ---\\n";\r\n\r\n    // 1. \u6700\u57fa\u672c\u7684\u7528\u6cd5\uff1a\u66ff\u6362\u5e76\u83b7\u53d6\u65e7\u503c\r\n    int x = 42;\r\n    int old_x = std::exchange(x, 100);\r\n    std::cout << "  \u65e7\u503c: " << old_x << "\\n";   // 42\r\n    std::cout << "  \u65b0\u503c: " << x << "\\n";         // 100\r\n\r\n    // 2. \u5b57\u7b26\u4e32\r\n    std::string s = "Hello";\r\n    std::string old_s = std::exchange(s, "World");\r\n    std::cout << "  \u65e7\u5b57\u7b26\u4e32: \\"" << old_s << "\\"\\n";   // Hello\r\n    std::cout << "  \u65b0\u5b57\u7b26\u4e32: \\"" << s << "\\"\\n";         // World\r\n\r\n    // 3. \u4e0e\u624b\u52a8\u5199\u6cd5\u5bf9\u6bd4\r\n    std::cout << "\\n  [\u4e0e\u624b\u52a8\u5199\u6cd5\u5bf9\u6bd4]\\n";\r\n\r\n    // \u624b\u52a8\u5199\u6cd5\r\n    int a = 10;\r\n    int temp = a;\r\n    a = 20;\r\n    std::cout << "  \u624b\u52a8: old=" << temp << ", new=" << a << "\\n";\r\n\r\n    // exchange\u5199\u6cd5\r\n    int b = 10;\r\n    int old_b = std::exchange(b, 20);\r\n    std::cout << "  exchange: old=" << old_b << ", new=" << b << "\\n";\r\n\r\n    // 4. \u7528\u4e8e"\u6d88\u8d39"\u4e00\u4e2a\u503c\r\n    bool flag = true;\r\n    if (std::exchange(flag, false)) {\r\n        std::cout << "\\n  flag\u66fe\u7ecf\u662ftrue\uff0c\u73b0\u5728\u5df2\u91cd\u7f6e\u4e3afalse\\n";\r\n    }\r\n    std::cout << "  flag = " << std::boolalpha << flag << "\\n";\r\n}\r\n\r\n// ============================================================\r\n// \u8fdb\u9636\u7528\u6cd5\r\n// ============================================================\r\n\r\n// 1. \u7b80\u5316\u79fb\u52a8\u6784\u9020\u51fd\u6570\u548c\u79fb\u52a8\u8d4b\u503c\u8fd0\u7b97\u7b26\r\nclass Buffer {\r\npublic:\r\n    Buffer() : data_(nullptr), size_(0), name_("empty") {\r\n        std::cout << "    Buffer() \u9ed8\u8ba4\u6784\u9020\\n";\r\n    }\r\n\r\n    explicit Buffer(std::size_t size, const std::string& name = "unnamed")\r\n        : data_(new int[size]()), size_(size), name_(name) {\r\n        std::cout << "    Buffer(\\"" << name_ << "\\", " << size_ << ") \u6784\u9020\\n";\r\n    }\r\n\r\n    ~Buffer() {\r\n        if (data_) {\r\n            std::cout << "    ~Buffer(\\"" << name_ << "\\") \u91ca\u653e " << size_ << " \u4e2aint\\n";\r\n        }\r\n        delete[] data_;\r\n    }\r\n\r\n    // \u79fb\u52a8\u6784\u9020\u51fd\u6570\u2014\u2014\u4f7f\u7528exchange\u7b80\u5316\r\n    Buffer(Buffer&& other) noexcept\r\n        : data_(std::exchange(other.data_, nullptr))    // \u53d6\u8d70\u6307\u9488\uff0c\u7f6e\u7a7a\u6e90\r\n        , size_(std::exchange(other.size_, 0))           // \u53d6\u8d70\u5927\u5c0f\uff0c\u5f52\u96f6\r\n        , name_(std::exchange(other.name_, "moved-from")) // \u53d6\u8d70\u540d\u5b57\uff0c\u6807\u8bb0\r\n    {\r\n        std::cout << "    Buffer(\\"" << name_ << "\\") \u79fb\u52a8\u6784\u9020\\n";\r\n    }\r\n\r\n    // \u79fb\u52a8\u8d4b\u503c\u8fd0\u7b97\u7b26\u2014\u2014\u4f7f\u7528exchange\u7b80\u5316\r\n    Buffer& operator=(Buffer&& other) noexcept {\r\n        if (this != &other) {\r\n            delete[] data_;  // \u91ca\u653e\u5f53\u524d\u8d44\u6e90\r\n\r\n            data_ = std::exchange(other.data_, nullptr);\r\n            size_ = std::exchange(other.size_, 0);\r\n            name_ = std::exchange(other.name_, "moved-from");\r\n            std::cout << "    Buffer(\\"" << name_ << "\\") \u79fb\u52a8\u8d4b\u503c\\n";\r\n        }\r\n        return *this;\r\n    }\r\n\r\n    // \u7981\u7528\u62f7\u8d1d\r\n    Buffer(const Buffer&) = delete;\r\n    Buffer& operator=(const Buffer&) = delete;\r\n\r\n    void info() const {\r\n        std::cout << "    [" << name_ << "] size=" << size_\r\n                  << ", data=" << (data_ ? "\u6709\u6548" : "\u7a7a") << "\\n";\r\n    }\r\n\r\n    std::size_t size() const { return size_; }\r\n    const std::string& name() const { return name_; }\r\n\r\nprivate:\r\n    int* data_;\r\n    std::size_t size_;\r\n    std::string name_;\r\n};\r\n\r\n// \u4e0d\u4f7f\u7528exchange\u7684\u79fb\u52a8\u6784\u9020\u51fd\u6570\u5bf9\u6bd4\r\nclass BufferOld {\r\npublic:\r\n    BufferOld() : data_(nullptr), size_(0) {}\r\n    explicit BufferOld(std::size_t size) : data_(new int[size]()), size_(size) {}\r\n    ~BufferOld() { delete[] data_; }\r\n\r\n    // \u4e0d\u7528exchange\u2014\u2014\u9700\u8981\u66f4\u591a\u4ee3\u7801\r\n    BufferOld(BufferOld&& other) noexcept\r\n        : data_(other.data_), size_(other.size_) {\r\n        other.data_ = nullptr;  // \u5fc5\u987b\u624b\u52a8\u7f6e\u7a7a\r\n        other.size_ = 0;        // \u5fc5\u987b\u624b\u52a8\u5f52\u96f6\r\n    }\r\n\r\n    BufferOld(const BufferOld&) = delete;\r\n    BufferOld& operator=(const BufferOld&) = delete;\r\n    BufferOld& operator=(BufferOld&&) = delete;\r\n\r\nprivate:\r\n    int* data_;\r\n    std::size_t size_;\r\n};\r\n\r\n// 2. \u94fe\u8868\u8282\u70b9\u7684\u6240\u6709\u6743\u8f6c\u79fb\r\nstruct ListNode {\r\n    int value;\r\n    std::unique_ptr<ListNode> next;\r\n\r\n    ListNode(int v, std::unique_ptr<ListNode> n = nullptr)\r\n        : value(v), next(std::move(n)) {}\r\n};\r\n\r\n// 3. \u72b6\u6001\u673a\u4e2d\u7684\u72b6\u6001\u8f6c\u6362\r\nclass StateMachine {\r\npublic:\r\n    enum class State { Idle, Running, Paused, Stopped };\r\n\r\n    State transition(State new_state) {\r\n        return std::exchange(state_, new_state);\r\n    }\r\n\r\n    State current() const { return state_; }\r\n\r\n    static const char* state_name(State s) {\r\n        switch (s) {\r\n            case State::Idle:    return "Idle";\r\n            case State::Running: return "Running";\r\n            case State::Paused:  return "Paused";\r\n            case State::Stopped: return "Stopped";\r\n            default:             return "Unknown";\r\n        }\r\n    }\r\n\r\nprivate:\r\n    State state_ = State::Idle;\r\n};\r\n\r\nvoid advanced_usage() {\r\n    std::cout << "\\n--- advanced_usage ---\\n";\r\n\r\n    // 1. \u79fb\u52a8\u6784\u9020\u51fd\u6570\u6f14\u793a\r\n    std::cout << "  [\u79fb\u52a8\u6784\u9020\u51fd\u6570]\\n";\r\n    Buffer buf1(1024, "original");\r\n    buf1.info();\r\n\r\n    Buffer buf2(std::move(buf1));\r\n    std::cout << "  \u79fb\u52a8\u540e:\\n";\r\n    buf1.info();  // moved-from\r\n    buf2.info();  // original\r\n\r\n    // \u79fb\u52a8\u8d4b\u503c\r\n    std::cout << "\\n  [\u79fb\u52a8\u8d4b\u503c\u8fd0\u7b97\u7b26]\\n";\r\n    Buffer buf3(512, "target");\r\n    buf3 = std::move(buf2);\r\n    std::cout << "  \u79fb\u52a8\u8d4b\u503c\u540e:\\n";\r\n    buf2.info();\r\n    buf3.info();\r\n\r\n    // 2. \u4f7f\u7528exchange\u5b9e\u73b0\u94fe\u8868\u53cd\u8f6c\r\n    std::cout << "\\n  [\u94fe\u8868\u64cd\u4f5c]\\n";\r\n    // \u6784\u5efa\u94fe\u8868: 1 -> 2 -> 3 -> 4\r\n    auto head = std::make_unique<ListNode>(1,\r\n        std::make_unique<ListNode>(2,\r\n            std::make_unique<ListNode>(3,\r\n                std::make_unique<ListNode>(4))));\r\n\r\n    // \u7528exchange\u53cd\u8f6c\u94fe\u8868\r\n    std::unique_ptr<ListNode> prev = nullptr;\r\n    auto current = std::move(head);\r\n    while (current) {\r\n        auto next = std::exchange(current->next, std::move(prev));\r\n        prev = std::exchange(current, std::move(next));\r\n    }\r\n    head = std::move(prev);\r\n\r\n    // \u6253\u5370\u53cd\u8f6c\u540e\u7684\u94fe\u8868\r\n    std::cout << "  \u53cd\u8f6c\u540e: ";\r\n    for (auto* p = head.get(); p; p = p->next.get()) {\r\n        std::cout << p->value << " ";\r\n    }\r\n    std::cout << "\\n";\r\n\r\n    // 3. \u72b6\u6001\u673a\r\n    std::cout << "\\n  [\u72b6\u6001\u673a\u8f6c\u6362]\\n";\r\n    StateMachine sm;\r\n    std::cout << "  \u5f53\u524d: " << StateMachine::state_name(sm.current()) << "\\n";\r\n\r\n    auto old = sm.transition(StateMachine::State::Running);\r\n    std::cout << "  \u8f6c\u6362: " << StateMachine::state_name(old)\r\n              << " -> " << StateMachine::state_name(sm.current()) << "\\n";\r\n\r\n    old = sm.transition(StateMachine::State::Paused);\r\n    std::cout << "  \u8f6c\u6362: " << StateMachine::state_name(old)\r\n              << " -> " << StateMachine::state_name(sm.current()) << "\\n";\r\n\r\n    old = sm.transition(StateMachine::State::Stopped);\r\n    std::cout << "  \u8f6c\u6362: " << StateMachine::state_name(old)\r\n              << " -> " << StateMachine::state_name(sm.current()) << "\\n";\r\n\r\n    // 4. \u6d88\u8d39\u961f\u5217\u2014\u2014\u53d6\u51fa\u6240\u6709\u5143\u7d20\r\n    std::cout << "\\n  [\u6d88\u8d39\u961f\u5217]\\n";\r\n    std::queue<int> q;\r\n    q.push(10);\r\n    q.push(20);\r\n    q.push(30);\r\n\r\n    // \u7528exchange\u4e00\u6b21\u6027\u53d6\u8d70\u6574\u4e2a\u961f\u5217\r\n    auto consumed = std::exchange(q, std::queue<int>{});\r\n    std::cout << "  \u539f\u961f\u5217\u5927\u5c0f: " << q.size() << " (\u5df2\u6e05\u7a7a)\\n";\r\n    std::cout << "  \u6d88\u8d39\u7684\u5143\u7d20: ";\r\n    while (!consumed.empty()) {\r\n        std::cout << consumed.front() << " ";\r\n        consumed.pop();\r\n    }\r\n    std::cout << "\\n";\r\n\r\n    std::cout << "\\n  --- \u6790\u6784\u6f14\u793a ---\\n";\r\n}\r\n\r\n// ============================================================\r\n// \u6613\u9519\u70b9\u4e0e\u9677\u9631\r\n// ============================================================\r\nvoid pitfalls() {\r\n    std::cout << "\\n--- pitfalls ---\\n";\r\n\r\n    // \u9677\u96311\uff1aexchange\u4e0d\u662f\u539f\u5b50\u64cd\u4f5c\r\n    std::cout << "  \u9677\u96311: std::exchange\u4e0d\u662f\u539f\u5b50\u64cd\u4f5c\\n";\r\n    std::cout << "    \u591a\u7ebf\u7a0b\u73af\u5883\u4e2d\u9700\u8981\u989d\u5916\u7684\u540c\u6b65\u673a\u5236\\n";\r\n    std::cout << "    \u539f\u5b50\u4ea4\u6362\u8bf7\u4f7f\u7528 std::atomic::exchange()\\n";\r\n\r\n    // \u9677\u96312\uff1aexchange\u7684\u7b2c\u4e8c\u4e2a\u53c2\u6570\u4f1a\u88ab\u79fb\u52a8/\u62f7\u8d1d\u5230\u76ee\u6807\r\n    std::cout << "\\n  \u9677\u96312: \u6ce8\u610fnew_value\u7684\u751f\u547d\u5468\u671f\\n";\r\n    std::string original = "Hello";\r\n    std::string replacement = "World";\r\n    auto old = std::exchange(original, std::move(replacement));\r\n    std::cout << "    old = \\"" << old << "\\"\\n";\r\n    std::cout << "    original = \\"" << original << "\\"\\n";\r\n    std::cout << "    replacement = \\"" << replacement << "\\" (\u5df2\u88ab\u79fb\u52a8)\\n";\r\n\r\n    // \u9677\u96313\uff1a\u81ea\u8d4b\u503c\u573a\u666f\r\n    std::cout << "\\n  \u9677\u96313: exchange\u4e0d\u68c0\u67e5\u81ea\u8d4b\u503c\\n";\r\n    int val = 42;\r\n    int result = std::exchange(val, val);  // \u867d\u7136\u65e0\u610f\u4e49\u4f46\u5408\u6cd5\r\n    std::cout << "    exchange(42, 42): old=" << result << ", new=" << val << "\\n";\r\n\r\n    // \u9677\u96314\uff1a\u4e0d\u8981\u4e0estd::swap\u6df7\u6dc6\r\n    std::cout << "\\n  \u9677\u96314: exchange vs swap\\n";\r\n    int a = 10, b = 20;\r\n    // exchange: \u5355\u5411\u66ff\u6362\uff0c\u8fd4\u56de\u65e7\u503c\r\n    int old_a = std::exchange(a, 99);\r\n    std::cout << "    exchange(a=10, 99): old_a=" << old_a << ", a=" << a << "\\n";\r\n\r\n    // swap: \u53cc\u5411\u4ea4\u6362\r\n    a = 10; b = 20;\r\n    std::swap(a, b);\r\n    std::cout << "    swap(10, 20): a=" << a << ", b=" << b << "\\n";\r\n\r\n    // \u9677\u96315\uff1a\u8fd4\u56de\u503c\u4e0d\u4f7f\u7528\u65f6\u7684\u8b66\u544a\r\n    std::cout << "\\n  \u9677\u96315: \u5982\u679c\u4e0d\u9700\u8981\u65e7\u503c\uff0c\u76f4\u63a5\u8d4b\u503c\u66f4\u597d\\n";\r\n    std::cout << "    std::exchange(x, 0);  // \u4e0d\u4f7f\u7528\u8fd4\u56de\u503c\u2014\u2014\u4e0d\u5982\u76f4\u63a5 x = 0;\\n";\r\n    std::cout << "    exchange\u7684\u4ef7\u503c\u5728\u4e8e\u540c\u65f6\u83b7\u53d6\u65e7\u503c\\n";\r\n}\r\n\r\n// ============================================================\r\n// \u4e3b\u51fd\u6570\r\n// ============================================================\r\nint main() {\r\n    std::cout << "===== std::exchange - C++14 =====\\n\\n";\r\n\r\n    basic_usage();\r\n    advanced_usage();\r\n    pitfalls();\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,a.jsx)(e.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,a.jsxs)(e.ul,{children:["\n",(0,a.jsx)(e.li,{children:(0,a.jsx)(e.a,{href:"https://en.cppreference.com/w/cpp/utility/exchange",children:"cppreference: std::exchange"})}),"\n"]})]})}function l(n={}){const{wrapper:e}={...(0,s.R)(),...n.components};return e?(0,a.jsx)(e,{...n,children:(0,a.jsx)(i,{...n})}):i(n)}},28453(n,e,r){r.d(e,{R:()=>d,x:()=>c});var t=r(96540);const a={},s=t.createContext(a);function d(n){const e=t.useContext(s);return t.useMemo(function(){return"function"==typeof n?n(e):{...e,...n}},[e,n])}function c(n){let e;return e=n.disableParentContext?"function"==typeof n.components?n.components(a):n.components||a:d(n.components),t.createElement(s.Provider,{value:e},n.children)}}}]);